120: // Helper function to update platform_posts based on TikTok publish_id
121: async function updatePlatformPostStatus(
122:   supabase: any,
123:   publishId: string,
124:   status: 'success' | 'failed',
125:   errorMessage: string | null,
126:   webhookData: any
127: ) {
128:   try {
129:     // Find platform_post with this publish_id in response_data
130:     const { data: platformPosts, error: findError } = await supabase
131:       .from('platform_posts')
132:       .select('id, post_id, response_data')
133:       .eq('platform', 'tiktok')
134:       .or(`response_data->>tiktok_publish_id.eq.${publishId},response_data->>publish_id.eq.${publishId}`);
135: 
136:     if (findError) {
137:       console.error('Error finding platform_post:', findError);
138:       return;
139:     }
140: 
141:     if (!platformPosts || platformPosts.length === 0) {
142:       console.log('No platform_post found for publish_id:', publishId);
143:       return;
144:     }
145: 
146:     for (const platformPost of platformPosts) {
147:       console.log(`Updating platform_post ${platformPost.id} to status: ${status}`);
148:       
149:       const updateData: any = {
150:         status,
151:         posted_at: status === 'success' ? new Date().toISOString() : null,
152:         response_data: {
153:           ...platformPost.response_data,
154:           webhook_event: webhookData,
155:           final_status: status,
156:           updated_at: new Date().toISOString(),
157:         },
158:       };
159: 
160:       if (errorMessage) {
161:         updateData.error_message = errorMessage;
162:       }
163: 
164:       // If success and we have video_id, set the post URL
165:       if (status === 'success' && webhookData.video_id) {
166:         updateData.platform_post_id = webhookData.video_id;
167:         // We don't have username here, so URL will be built in frontend
168:       }
169: 
170:       const { error: updateError } = await supabase
171:         .from('platform_posts')
172:         .update(updateData)
173:         .eq('id', platformPost.id);
174: 
175:       if (updateError) {
176:         console.error('Error updating platform_post:', updateError);
177:         continue;
178:       }
179: 
180:       // Also update the parent post status
181:       await updateParentPostStatus(supabase, platformPost.post_id);
182:     }
183:   } catch (error) {
184:     console.error('Error in updatePlatformPostStatus:', error);
185:   }
186: }
